-- Inventory & Custody Core — Phase One.
-- This migration deliberately establishes only the shared catalog, location and
-- append-only stock-ledger foundation. Transfers, custody, reservations, import
-- posting, reconciliation and CAPA adapters are deferred to later migrations.

do $$ begin create type public.inventory_recording_channel as enum ('system','legacy_off_system'); exception when duplicate_object then null; end $$;
do $$ begin create type public.inventory_stock_disposition as enum ('available','reserved','quarantine','damaged','expired','returns_hold','wastage_hold','transit'); exception when duplicate_object then null; end $$;
do $$ begin create type public.inventory_lot_status as enum ('known','pending','unknown_legacy','not_applicable'); exception when duplicate_object then null; end $$;
do $$ begin create type public.inventory_expiry_status as enum ('known_valid','pending','unknown_legacy','expired','quarantined','not_applicable'); exception when duplicate_object then null; end $$;
do $$ begin create type public.inventory_location_kind as enum ('storage','department','pharmacy','controlled','transit'); exception when duplicate_object then null; end $$;
do $$ begin create type public.inventory_account_type as enum ('physical','external_control'); exception when duplicate_object then null; end $$;
do $$ begin create type public.inventory_command_status as enum ('draft','submitted','approved','rejected','posted'); exception when duplicate_object then null; end $$;
do $$ begin create type public.inventory_transaction_type as enum ('opening','migration','reversal','batch_split','batch_attribute'); exception when duplicate_object then null; end $$;

insert into public.permissions(key,name_ar,name_en) values
 ('inventory.view','عرض المخزون','View inventory'),
 ('inventory.view_ledger','عرض دفتر حركات المخزون','View inventory ledger detail'),
 ('inventory.view_confidential','عرض المخزون السري','View confidential inventory'),
 ('inventory.manage_catalog','إدارة دليل الأصناف','Manage inventory catalog'),
 ('inventory.manage_locations','إدارة مواقع المخزون','Manage inventory locations'),
 ('inventory.post_opening','ترحيل رصيد افتتاحي','Post inventory opening or migration'),
 ('inventory.approve_opening','اعتماد رصيد افتتاحي','Approve inventory opening or migration'),
 ('inventory.reverse','عكس حركة مخزون','Reverse inventory transaction')
on conflict(key) do nothing;
insert into public.role_permissions(role_id,permission_id)
select r.id,p.id from public.roles r join public.permissions p on p.key like 'inventory.%'
where r.key='platform_owner' on conflict do nothing;

create table public.catalog_items (
 id uuid primary key default gen_random_uuid(),
 item_name_ar text, item_name_en text not null,
 manufacturer_name text, default_controlled_classification text not null default 'standard' check(default_controlled_classification in ('standard','controlled')),
 classification_authority text, classification_version text,
 active boolean not null default true, created_at timestamptz not null default now(), created_by uuid references public.user_profiles(id),
 updated_at timestamptz not null default now(), updated_by uuid references public.user_profiles(id),
 check(coalesce(nullif(trim(item_name_ar),''),nullif(trim(item_name_en),'')) is not null)
);
create table public.catalog_item_identifiers (
 id uuid primary key default gen_random_uuid(), catalog_item_id uuid not null references public.catalog_items(id) on delete restrict,
 identifier_type text not null check(identifier_type in ('nupco','moh','manufacturer','local')),
 identifier_value text not null, normalized_identifier_value text not null, authority text, source_context text, authoritative boolean not null default false, active boolean not null default true,
 created_at timestamptz not null default now(), created_by uuid references public.user_profiles(id),
 unique(catalog_item_id,identifier_type,normalized_identifier_value,source_context),
 check((authoritative and nullif(trim(authority),'') is not null) or (not authoritative and nullif(trim(source_context),'') is not null))
);
create unique index catalog_item_authoritative_identifier_once on public.catalog_item_identifiers(authority,identifier_type,normalized_identifier_value) where authoritative and active;

create table public.inventory_units (
 id uuid primary key default gen_random_uuid(), code text not null unique, name_ar text, name_en text not null, active boolean not null default true,
 created_at timestamptz not null default now(), created_by uuid references public.user_profiles(id)
);
create table public.inventory_item_profiles (
 id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id), organization_id uuid not null references public.organizations(id), facility_id uuid not null references public.facilities(id),
 catalog_item_id uuid not null references public.catalog_items(id), operational_controlled_classification text not null default 'standard' check(operational_controlled_classification in ('standard','controlled')),
 classification_authority text, classification_version text, confidentiality_level text not null default 'normal' check(confidentiality_level in ('normal','confidential','restricted')),
 active boolean not null default false, created_at timestamptz not null default now(), created_by uuid not null references public.user_profiles(id), updated_at timestamptz not null default now(), updated_by uuid not null references public.user_profiles(id),
 unique(tenant_id,organization_id,facility_id,catalog_item_id)
);
create table public.inventory_item_units (
 id uuid primary key default gen_random_uuid(), inventory_item_profile_id uuid not null references public.inventory_item_profiles(id) on delete restrict,
 inventory_unit_id uuid not null references public.inventory_units(id), multiplier_to_base numeric(20,6) not null check(multiplier_to_base > 0), is_base_unit boolean not null default false, active boolean not null default true,
 created_at timestamptz not null default now(), created_by uuid references public.user_profiles(id), updated_at timestamptz not null default now(), updated_by uuid references public.user_profiles(id),
 unique(inventory_item_profile_id,inventory_unit_id), check(not is_base_unit or multiplier_to_base=1)
);
create unique index inventory_item_units_one_active_base on public.inventory_item_units(inventory_item_profile_id) where active and is_base_unit;

create or replace function public.enforce_inventory_item_profile_scope() returns trigger language plpgsql security definer set search_path=public as $$
begin if not exists(select 1 from public.facilities f where f.id=new.facility_id and f.tenant_id=new.tenant_id and f.organization_id=new.organization_id) then raise exception 'Inventory item profile facility scope mismatch' using errcode='23503'; end if; return new; end $$;
create trigger inventory_item_profile_scope before insert or update on public.inventory_item_profiles for each row execute function public.enforce_inventory_item_profile_scope();

create table public.inventory_locations (
 id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id), organization_id uuid not null references public.organizations(id), facility_id uuid not null references public.facilities(id), department_id uuid references public.departments(id),
 parent_location_id uuid references public.inventory_locations(id) on delete restrict, code text not null, name_ar text, name_en text not null,
 location_kind public.inventory_location_kind not null default 'storage', confidential boolean not null default false, protected_transit boolean not null default false, active boolean not null default true,
 created_at timestamptz not null default now(), created_by uuid not null references public.user_profiles(id), updated_at timestamptz not null default now(), updated_by uuid references public.user_profiles(id),
 unique(tenant_id,organization_id,facility_id,code), check(not protected_transit or location_kind='transit')
);
create table public.inventory_location_attributes (
 location_id uuid primary key references public.inventory_locations(id) on delete cascade,
 attributes jsonb not null default '{}'::jsonb, updated_at timestamptz not null default now(), updated_by uuid references public.user_profiles(id),
 check(not (attributes ?| array['password','token','secret','access_token']))
);

create table public.inventory_batches (
 id uuid primary key default gen_random_uuid(), inventory_item_profile_id uuid not null references public.inventory_item_profiles(id) on delete restrict,
 manufacturer_name text, lot_number text, lot_status public.inventory_lot_status not null default 'pending', expiry_date date, expiry_status public.inventory_expiry_status not null default 'pending',
 parent_batch_id uuid references public.inventory_batches(id) on delete restrict, active boolean not null default true,
 created_at timestamptz not null default now(), created_by uuid not null references public.user_profiles(id), updated_at timestamptz not null default now(), updated_by uuid references public.user_profiles(id),
 check((lot_status='known' and nullif(trim(lot_number),'') is not null) or (lot_status<>'known' and nullif(trim(lot_number),'') is null)),
 check((expiry_status in ('known_valid','expired') and expiry_date is not null) or (expiry_status in ('pending','unknown_legacy','quarantined','not_applicable') and expiry_date is null))
);
create unique index inventory_batches_known_lot_unique on public.inventory_batches(inventory_item_profile_id,lot_number) where lot_status='known' and active;
create table public.inventory_batch_splits (
 id uuid primary key default gen_random_uuid(), parent_batch_id uuid not null references public.inventory_batches(id) on delete restrict, child_batch_id uuid not null unique references public.inventory_batches(id) on delete restrict,
 transaction_id uuid, quantity_base numeric(20,6) not null check(quantity_base>0), reason text not null, created_at timestamptz not null default now(), created_by uuid not null references public.user_profiles(id)
);

create table public.inventory_commands (
 id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id), organization_id uuid not null references public.organizations(id), facility_id uuid not null references public.facilities(id),
 command_type public.inventory_transaction_type not null check(command_type in ('opening','migration','reversal','batch_split','batch_attribute')),
 status public.inventory_command_status not null default 'draft', requester_id uuid not null references public.user_profiles(id), approver_id uuid references public.user_profiles(id),
 idempotency_key text not null, request_hash text not null check(length(request_hash)>=16), payload jsonb not null, result_transaction_id uuid, reason text,
 created_at timestamptz not null default now(), submitted_at timestamptz, approved_at timestamptz, posted_at timestamptz,
 unique(tenant_id,organization_id,facility_id,requester_id,idempotency_key)
);
create table public.inventory_transactions (
 id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id), organization_id uuid not null references public.organizations(id), facility_id uuid not null references public.facilities(id),
 command_id uuid unique references public.inventory_commands(id) on delete restrict, transaction_type public.inventory_transaction_type not null, posted_by uuid not null references public.user_profiles(id), posted_at timestamptz not null default now(), reason text,
 reverses_transaction_id uuid unique references public.inventory_transactions(id) on delete restrict, reversal_transaction_id uuid unique references public.inventory_transactions(id) on delete restrict,
 metadata jsonb not null default '{}'::jsonb, check(not (metadata ?| array['password','token','secret','access_token']))
);
alter table public.inventory_commands add constraint inventory_commands_result_transaction_fk foreign key(result_transaction_id) references public.inventory_transactions(id) on delete restrict;
alter table public.inventory_batch_splits add constraint inventory_batch_splits_transaction_fk foreign key(transaction_id) references public.inventory_transactions(id) on delete restrict;
create table public.inventory_ledger_entries (
 id uuid primary key default gen_random_uuid(), transaction_id uuid not null references public.inventory_transactions(id) on delete restrict,
 inventory_item_profile_id uuid not null references public.inventory_item_profiles(id), batch_id uuid references public.inventory_batches(id) on delete restrict,
 inventory_item_unit_id uuid not null references public.inventory_item_units(id), recording_channel public.inventory_recording_channel not null,
 account_type public.inventory_account_type not null, location_id uuid references public.inventory_locations(id) on delete restrict, disposition public.inventory_stock_disposition,
 quantity_base numeric(20,6) not null check(quantity_base<>0), created_at timestamptz not null default now(),
 check((account_type='physical' and location_id is not null and disposition is not null) or (account_type='external_control' and location_id is null and disposition is null))
);
create table public.inventory_balance_projections (
 id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id), organization_id uuid not null references public.organizations(id), facility_id uuid not null references public.facilities(id),
 location_id uuid not null references public.inventory_locations(id), inventory_item_profile_id uuid not null references public.inventory_item_profiles(id), batch_id uuid references public.inventory_batches(id),
 recording_channel public.inventory_recording_channel not null, disposition public.inventory_stock_disposition not null, quantity_base numeric(20,6) not null default 0 check(quantity_base>=0), updated_at timestamptz not null default now(),
 unique nulls not distinct(location_id,inventory_item_profile_id,batch_id,recording_channel,disposition)
);
create table public.inventory_events (
 id uuid primary key default gen_random_uuid(), transaction_id uuid not null references public.inventory_transactions(id) on delete restrict,
 tenant_id uuid not null references public.tenants(id), organization_id uuid not null references public.organizations(id), facility_id uuid not null references public.facilities(id),
 actor_id uuid not null references public.user_profiles(id), action text not null, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(),
 check(not (metadata ?| array['password','token','secret','access_token']))
);

create or replace function public.can_manage_inventory_item_profile(p_t uuid,p_o uuid,p_f uuid) returns boolean language sql stable security definer set search_path=public as $$
 select auth.uid() is not null and public.scope_allowed(p_t,p_o,p_f) and (public.has_platform_permission('inventory.manage_catalog',p_t,p_o,p_f) or public.has_platform_permission('platform.full_access',p_t,p_o,p_f)); $$;
create or replace function public.can_manage_inventory_location(p_location uuid) returns boolean language sql stable security definer set search_path=public as $$
 select exists(select 1 from public.inventory_locations l where l.id=p_location and public.scope_allowed(l.tenant_id,l.organization_id,l.facility_id) and (public.has_platform_permission('inventory.manage_locations',l.tenant_id,l.organization_id,l.facility_id) or public.has_platform_permission('platform.full_access',l.tenant_id,l.organization_id,l.facility_id))); $$;
create or replace function public.can_view_inventory_location(p_location uuid) returns boolean language sql stable security definer set search_path=public as $$
 select exists(select 1 from public.inventory_locations l where l.id=p_location and public.scope_allowed(l.tenant_id,l.organization_id,l.facility_id) and (not l.confidential or public.has_platform_permission('inventory.view_confidential',l.tenant_id,l.organization_id,l.facility_id) or public.has_platform_permission('platform.full_access',l.tenant_id,l.organization_id,l.facility_id)) and (public.has_platform_permission('inventory.view',l.tenant_id,l.organization_id,l.facility_id) or public.can_manage_inventory_location(l.id) or public.has_platform_permission('platform.full_access',l.tenant_id,l.organization_id,l.facility_id))); $$;
create or replace function public.can_view_inventory_transaction(p_transaction uuid) returns boolean language sql stable security definer set search_path=public as $$
 select exists(select 1 from public.inventory_transactions t where t.id=p_transaction and public.scope_allowed(t.tenant_id,t.organization_id,t.facility_id) and (public.has_platform_permission('inventory.view',t.tenant_id,t.organization_id,t.facility_id) or public.has_platform_permission('platform.full_access',t.tenant_id,t.organization_id,t.facility_id))); $$;
create or replace function public.can_view_inventory_ledger_entry(p_entry uuid) returns boolean language sql stable security definer set search_path=public as $$
 select exists(select 1 from public.inventory_ledger_entries le join public.inventory_transactions tx on tx.id=le.transaction_id where le.id=p_entry and public.can_view_inventory_transaction(tx.id) and (public.has_platform_permission('inventory.view_ledger',tx.tenant_id,tx.organization_id,tx.facility_id) or public.has_platform_permission('platform.full_access',tx.tenant_id,tx.organization_id,tx.facility_id)) and (le.account_type='external_control' or public.can_view_inventory_location(le.location_id))); $$;
create or replace function public.can_view_inventory_command(p_command uuid) returns boolean language sql stable security definer set search_path=public as $$
 select exists(select 1 from public.inventory_commands c where c.id=p_command and public.scope_allowed(c.tenant_id,c.organization_id,c.facility_id) and (c.requester_id=auth.uid() or public.has_platform_permission('inventory.post_opening',c.tenant_id,c.organization_id,c.facility_id) or public.has_platform_permission('inventory.approve_opening',c.tenant_id,c.organization_id,c.facility_id) or public.has_platform_permission('platform.full_access',c.tenant_id,c.organization_id,c.facility_id))); $$;
create or replace function public.can_post_inventory_transaction(p_t uuid,p_o uuid,p_f uuid) returns boolean language sql stable security definer set search_path=public as $$
 select auth.uid() is not null and public.scope_allowed(p_t,p_o,p_f) and (public.has_platform_permission('inventory.post_opening',p_t,p_o,p_f) or public.has_platform_permission('platform.full_access',p_t,p_o,p_f)); $$;

create or replace function public.inventory_enforce_item_unit_base() returns trigger language plpgsql security definer set search_path=public as $$
declare p_id uuid:=case when tg_table_name='inventory_item_profiles' then coalesce((to_jsonb(new)->>'id')::uuid,(to_jsonb(old)->>'id')::uuid) else coalesce((to_jsonb(new)->>'inventory_item_profile_id')::uuid,(to_jsonb(old)->>'inventory_item_profile_id')::uuid) end; active_profile boolean; base_count integer; begin select ip.active into active_profile from public.inventory_item_profiles ip where ip.id=p_id; if coalesce(active_profile,false) then select count(*) into base_count from public.inventory_item_units iu where iu.inventory_item_profile_id=p_id and iu.active and iu.is_base_unit; if base_count<>1 then raise exception 'Active inventory item profile requires exactly one active base unit' using errcode='23514'; end if; end if; return null; end $$;
create constraint trigger inventory_item_unit_base_guard after insert or update or delete on public.inventory_item_units deferrable initially deferred for each row execute function public.inventory_enforce_item_unit_base();
create constraint trigger inventory_profile_base_guard after insert or update of active on public.inventory_item_profiles deferrable initially deferred for each row execute function public.inventory_enforce_item_unit_base();

create or replace function public.enforce_inventory_location_integrity() returns trigger language plpgsql security definer set search_path=public as $$
declare parent_row public.inventory_locations%rowtype; begin
 if not exists(select 1 from public.facilities f where f.id=new.facility_id and f.tenant_id=new.tenant_id and f.organization_id=new.organization_id) then raise exception 'Inventory location facility scope mismatch' using errcode='23503'; end if;
 if new.department_id is not null and not exists(select 1 from public.departments d where d.id=new.department_id and d.tenant_id=new.tenant_id and d.organization_id=new.organization_id and d.facility_id=new.facility_id) then raise exception 'Inventory location department scope mismatch' using errcode='23503'; end if;
 if new.parent_location_id is not null then select l.* into parent_row from public.inventory_locations l where l.id=new.parent_location_id; if not found or (parent_row.tenant_id,parent_row.organization_id,parent_row.facility_id) is distinct from (new.tenant_id,new.organization_id,new.facility_id) then raise exception 'Inventory location parent scope mismatch' using errcode='23503'; end if; if new.id=parent_row.id or exists(with recursive tree as (select l.id,l.parent_location_id from public.inventory_locations l where l.id=parent_row.id union all select c.id,c.parent_location_id from public.inventory_locations c join tree t on c.id=t.parent_location_id) select 1 from tree where id=new.id) then raise exception 'Inventory location hierarchy cycle' using errcode='23514'; end if; end if;
 if tg_op='UPDATE' and (old.parent_location_id is distinct from new.parent_location_id or old.tenant_id<>new.tenant_id or old.organization_id<>new.organization_id or old.facility_id<>new.facility_id or old.department_id is distinct from new.department_id or old.active<>new.active or (old.confidential and not new.confidential)) and (exists(select 1 from public.inventory_balance_projections p where p.location_id=old.id and p.quantity_base<>0) or exists(select 1 from public.inventory_ledger_entries e where e.location_id=old.id)) then raise exception 'Inventory location with ledger history cannot be structurally changed' using errcode='23514'; end if;
 if new.protected_transit and auth.role() not in ('service_role','postgres') then raise exception 'Protected transit location requires trusted setup' using errcode='42501'; end if; return new; end $$;
create trigger inventory_location_integrity before insert or update on public.inventory_locations for each row execute function public.enforce_inventory_location_integrity();

create or replace function public.enforce_inventory_batch_integrity() returns trigger language plpgsql security definer set search_path=public as $$
begin if tg_op='UPDATE' and (old.lot_number is distinct from new.lot_number or old.lot_status<>new.lot_status or old.expiry_date is distinct from new.expiry_date or old.expiry_status<>new.expiry_status) and current_setting('app.inventory_batch_controlled',true)<>'on' then raise exception 'Inventory batch lot and expiry changes require a controlled function' using errcode='42501'; end if; return new; end $$;
create trigger inventory_batch_integrity before update on public.inventory_batches for each row execute function public.enforce_inventory_batch_integrity();

create or replace function public.prevent_inventory_immutable_mutation() returns trigger language plpgsql security definer set search_path=public as $$ begin raise exception 'Posted inventory records are append-only' using errcode='42501'; end $$;
create trigger inventory_transactions_immutable before update or delete on public.inventory_transactions for each row when (current_setting('app.inventory_transaction_controlled',true)<>'on') execute function public.prevent_inventory_immutable_mutation();
create trigger inventory_ledger_entries_immutable before update or delete on public.inventory_ledger_entries for each row execute function public.prevent_inventory_immutable_mutation();
create trigger inventory_events_immutable before update or delete on public.inventory_events for each row execute function public.prevent_inventory_immutable_mutation();
create trigger inventory_projection_immutable before update or delete on public.inventory_balance_projections for each row when (current_setting('app.inventory_projection_controlled',true)<>'on') execute function public.prevent_inventory_immutable_mutation();

create or replace function public.inventory_write_event_and_audit(p_transaction uuid,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$
declare tx public.inventory_transactions%rowtype; begin select t.* into tx from public.inventory_transactions t where t.id=p_transaction; if not found or p_metadata ?| array['password','token','secret','access_token'] then raise exception 'Inventory audit write denied'; end if; insert into public.inventory_events(transaction_id,tenant_id,organization_id,facility_id,actor_id,action,metadata) values(tx.id,tx.tenant_id,tx.organization_id,tx.facility_id,tx.posted_by,p_action,p_metadata); insert into public.audit_events(tenant_id,organization_id,facility_id,actor_id,action,entity_type,entity_id,metadata) values(tx.tenant_id,tx.organization_id,tx.facility_id,tx.posted_by,p_action,'inventory_transaction',tx.id,p_metadata); end $$;

create or replace function public.inventory_apply_projection(p_entry public.inventory_ledger_entries) returns void language plpgsql security definer set search_path=public as $$
declare q numeric(20,6); begin if p_entry.account_type<>'physical' then return; end if; perform pg_advisory_xact_lock(hashtextextended(concat_ws('|',p_entry.location_id::text,p_entry.inventory_item_profile_id::text,coalesce(p_entry.batch_id::text,'∅'),p_entry.recording_channel::text,p_entry.disposition::text),0)); select bp.quantity_base into q from public.inventory_balance_projections bp where bp.location_id=p_entry.location_id and bp.inventory_item_profile_id=p_entry.inventory_item_profile_id and bp.batch_id is not distinct from p_entry.batch_id and bp.recording_channel=p_entry.recording_channel and bp.disposition=p_entry.disposition for update; perform set_config('app.inventory_projection_controlled','on',true); if found then q:=q+p_entry.quantity_base; if q<0 then raise exception 'Inventory posting would create negative physical balance' using errcode='23514'; end if; update public.inventory_balance_projections bp set quantity_base=q,updated_at=now() where bp.location_id=p_entry.location_id and bp.inventory_item_profile_id=p_entry.inventory_item_profile_id and bp.batch_id is not distinct from p_entry.batch_id and bp.recording_channel=p_entry.recording_channel and bp.disposition=p_entry.disposition; else if p_entry.quantity_base<0 then raise exception 'Inventory posting would create negative physical balance' using errcode='23514'; end if; insert into public.inventory_balance_projections(tenant_id,organization_id,facility_id,location_id,inventory_item_profile_id,batch_id,recording_channel,disposition,quantity_base) select ip.tenant_id,ip.organization_id,ip.facility_id,p_entry.location_id,p_entry.inventory_item_profile_id,p_entry.batch_id,p_entry.recording_channel,p_entry.disposition,p_entry.quantity_base from public.inventory_item_profiles ip where ip.id=p_entry.inventory_item_profile_id; end if; end $$;

create or replace function public.inventory_post_entries(p_transaction uuid,p_entries jsonb,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$
declare tx public.inventory_transactions%rowtype; e jsonb; balanced boolean; profile public.inventory_item_profiles%rowtype; unit public.inventory_item_units%rowtype; batch public.inventory_batches%rowtype; inserted public.inventory_ledger_entries%rowtype; begin
 select t.* into tx from public.inventory_transactions t where t.id=p_transaction for update; if not found then raise exception 'Inventory transaction not found'; end if;
 for e in select value from jsonb_array_elements(p_entries) loop
  select ip.* into profile from public.inventory_item_profiles ip where ip.id=(e->>'profile_id')::uuid and (ip.tenant_id,ip.organization_id,ip.facility_id)=(tx.tenant_id,tx.organization_id,tx.facility_id); if not found then raise exception 'Inventory entry profile scope mismatch'; end if; select iu.* into unit from public.inventory_item_units iu where iu.id=(e->>'unit_id')::uuid and iu.inventory_item_profile_id=profile.id and iu.active and iu.is_base_unit; if not found then raise exception 'Inventory entry requires the active base unit'; end if;
  if nullif(e->>'batch_id','') is not null then select b.* into batch from public.inventory_batches b where b.id=(e->>'batch_id')::uuid and b.inventory_item_profile_id=profile.id; if not found then raise exception 'Inventory batch scope mismatch'; end if; else batch:=null; end if;
  if (e->>'account_type')='physical' and not exists(select 1 from public.inventory_locations l where l.id=nullif(e->>'location_id','')::uuid and (l.tenant_id,l.organization_id,l.facility_id)=(tx.tenant_id,tx.organization_id,tx.facility_id)) then raise exception 'Inventory entry location scope mismatch'; end if;
  if profile.operational_controlled_classification='controlled' and (batch.id is null or batch.lot_status<>'known' or batch.expiry_status<>'known_valid') then raise exception 'Controlled inventory requires a complete known lot and expiry'; end if;
  insert into public.inventory_ledger_entries(transaction_id,inventory_item_profile_id,batch_id,inventory_item_unit_id,recording_channel,account_type,location_id,disposition,quantity_base) values(tx.id,profile.id,batch.id,unit.id,(e->>'channel')::public.inventory_recording_channel,(e->>'account_type')::public.inventory_account_type,nullif(e->>'location_id','')::uuid,nullif(e->>'disposition','')::public.inventory_stock_disposition,(e->>'quantity_base')::numeric) returning * into inserted; perform public.inventory_apply_projection(inserted);
 end loop;
 select coalesce(bool_and(s.quantity_base=0),false) into balanced from (select sum(le.quantity_base) quantity_base from public.inventory_ledger_entries le where le.transaction_id=tx.id group by le.inventory_item_profile_id,le.batch_id,le.recording_channel,le.inventory_item_unit_id) s; if not balanced then raise exception 'Inventory transaction is not balanced at the required grain' using errcode='23514'; end if;
 perform public.inventory_write_event_and_audit(tx.id,p_action,p_metadata); end $$;

create or replace function public.create_catalog_item(p_name_ar text,p_name_en text,p_manufacturer text default null,p_default_controlled text default 'standard',p_authority text default null,p_version text default null) returns uuid language plpgsql security definer set search_path=public as $$
declare r uuid; begin if auth.uid() is null or not (public.has_platform_permission('platform.manage_reference_data',null,null,null) or exists(select 1 from public.user_role_assignments ura join public.roles r on r.id=ura.role_id where ura.user_id=auth.uid() and ura.active and r.key='platform_owner') or public.has_platform_permission('platform.full_access',null,null,null)) or coalesce(nullif(trim(p_name_ar),''),nullif(trim(p_name_en),'')) is null or p_default_controlled not in ('standard','controlled') then raise exception 'Catalog item creation denied'; end if; insert into public.catalog_items(item_name_ar,item_name_en,manufacturer_name,default_controlled_classification,classification_authority,classification_version,created_by,updated_by) values(nullif(trim(p_name_ar),''),coalesce(nullif(trim(p_name_en),''),'Item'),nullif(trim(p_manufacturer),''),p_default_controlled,nullif(trim(p_authority),''),nullif(trim(p_version),''),auth.uid(),auth.uid()) returning id into r; return r; end $$;
create or replace function public.normalize_catalog_identifier(p_value text) returns text language sql immutable set search_path=public as $$ select upper(regexp_replace(trim(p_value),'\s+',' ','g')); $$;
create or replace function public.enforce_catalog_identifier_normalization() returns trigger language plpgsql security definer set search_path=public as $$ begin new.normalized_identifier_value:=public.normalize_catalog_identifier(new.identifier_value); new.authority:=nullif(upper(trim(coalesce(new.authority,''))),'' ); new.source_context:=nullif(lower(trim(coalesce(new.source_context,''))),'' ); return new; end $$;
create trigger catalog_identifier_normalization before insert or update on public.catalog_item_identifiers for each row execute function public.enforce_catalog_identifier_normalization();
create or replace function public.add_catalog_item_identifier(p_item uuid,p_type text,p_value text,p_authority text default null,p_source_context text default null,p_authoritative boolean default false) returns uuid language plpgsql security definer set search_path=public as $$
declare r uuid; normalized text:=public.normalize_catalog_identifier(p_value); begin if auth.uid() is null or not exists(select 1 from public.catalog_items ci where ci.id=p_item) or p_type not in ('nupco','moh','manufacturer','local') or normalized='' or (p_authoritative and coalesce(trim(p_authority),'')='') or (not p_authoritative and coalesce(trim(p_source_context),'')='') or not (exists(select 1 from public.user_role_assignments ura join public.roles ro on ro.id=ura.role_id where ura.user_id=auth.uid() and ura.active and ro.key='platform_owner') or public.has_platform_permission('platform.manage_reference_data',null,null,null)) then raise exception 'Catalog identifier creation denied'; end if; insert into public.catalog_item_identifiers(catalog_item_id,identifier_type,identifier_value,normalized_identifier_value,authority,source_context,authoritative,created_by) values(p_item,p_type,trim(p_value),normalized,nullif(trim(p_authority),''),nullif(trim(p_source_context),''),p_authoritative,auth.uid()) returning id into r; return r; end $$;
create or replace function public.create_inventory_unit(p_code text,p_name_ar text,p_name_en text) returns uuid language plpgsql security definer set search_path=public as $$
declare r uuid; begin if auth.uid() is null or coalesce(trim(p_code),'')='' or coalesce(nullif(trim(p_name_ar),''),nullif(trim(p_name_en),'')) is null or not exists(select 1 from public.user_role_assignments ura join public.roles ro on ro.id=ura.role_id where ura.user_id=auth.uid() and ura.active and ro.key='platform_owner') then raise exception 'Inventory unit creation denied'; end if; insert into public.inventory_units(code,name_ar,name_en,created_by) values(trim(p_code),nullif(trim(p_name_ar),''),coalesce(nullif(trim(p_name_en),''),'Unit'),auth.uid()) returning id into r; return r; end $$;
create or replace function public.create_inventory_item_profile(p_t uuid,p_o uuid,p_f uuid,p_catalog_item uuid,p_initial_base_unit uuid,p_controlled text,p_authority text,p_version text,p_confidentiality text default 'normal') returns uuid language plpgsql security definer set search_path=public as $$
declare r uuid; begin if not public.can_manage_inventory_item_profile(p_t,p_o,p_f) or not exists(select 1 from public.catalog_items ci where ci.id=p_catalog_item and ci.active) or not exists(select 1 from public.inventory_units u where u.id=p_initial_base_unit and u.active) or p_controlled not in ('standard','controlled') or p_confidentiality not in ('normal','confidential','restricted') then raise exception 'Inventory profile creation denied'; end if; insert into public.inventory_item_profiles(tenant_id,organization_id,facility_id,catalog_item_id,operational_controlled_classification,classification_authority,classification_version,confidentiality_level,active,created_by,updated_by) values(p_t,p_o,p_f,p_catalog_item,p_controlled,nullif(trim(p_authority),''),nullif(trim(p_version),''),p_confidentiality,false,auth.uid(),auth.uid()) returning id into r; insert into public.inventory_item_units(inventory_item_profile_id,inventory_unit_id,multiplier_to_base,is_base_unit,active,created_by,updated_by) values(r,p_initial_base_unit,1,true,true,auth.uid(),auth.uid()); update public.inventory_item_profiles ip set active=true,updated_at=now(),updated_by=auth.uid() where ip.id=r; return r; end $$;
create or replace function public.configure_inventory_item_unit(p_profile uuid,p_unit uuid,p_multiplier numeric,p_is_base boolean,p_active boolean default true) returns uuid language plpgsql security definer set search_path=public as $$
declare profile public.inventory_item_profiles%rowtype; r uuid; begin select ip.* into profile from public.inventory_item_profiles ip where ip.id=p_profile for update; if not found or not public.can_manage_inventory_item_profile(profile.tenant_id,profile.organization_id,profile.facility_id) or p_multiplier<=0 or (p_is_base and p_multiplier<>1) then raise exception 'Inventory item unit configuration denied'; end if; insert into public.inventory_item_units(inventory_item_profile_id,inventory_unit_id,multiplier_to_base,is_base_unit,active,created_by,updated_by) values(p_profile,p_unit,p_multiplier,p_is_base,p_active,auth.uid(),auth.uid()) on conflict(inventory_item_profile_id,inventory_unit_id) do update set multiplier_to_base=excluded.multiplier_to_base,is_base_unit=excluded.is_base_unit,active=excluded.active,updated_at=now(),updated_by=auth.uid() returning id into r; return r; end $$;
create or replace function public.create_inventory_location(p_t uuid,p_o uuid,p_f uuid,p_department uuid,p_parent uuid,p_code text,p_name_ar text,p_name_en text,p_kind public.inventory_location_kind,p_confidential boolean default false) returns uuid language plpgsql security definer set search_path=public as $$
declare r uuid; begin if not public.can_manage_inventory_item_profile(p_t,p_o,p_f) and not (auth.uid() is not null and public.scope_allowed(p_t,p_o,p_f) and (public.has_platform_permission('inventory.manage_locations',p_t,p_o,p_f) or public.has_platform_permission('platform.full_access',p_t,p_o,p_f))) or coalesce(trim(p_code),'')='' or coalesce(nullif(trim(p_name_ar),''),nullif(trim(p_name_en),'')) is null or p_kind='transit' then raise exception 'Inventory location creation denied'; end if; insert into public.inventory_locations(tenant_id,organization_id,facility_id,department_id,parent_location_id,code,name_ar,name_en,location_kind,confidential,created_by,updated_by) values(p_t,p_o,p_f,p_department,p_parent,trim(p_code),nullif(trim(p_name_ar),''),coalesce(nullif(trim(p_name_en),''),'Location'),p_kind,p_confidential,auth.uid(),auth.uid()) returning id into r; return r; end $$;

create or replace function public.create_inventory_opening_command(p_t uuid,p_o uuid,p_f uuid,p_type public.inventory_transaction_type,p_entries jsonb,p_idempotency_key text,p_request_hash text,p_reason text default null) returns uuid language plpgsql security definer set search_path=public as $$
declare c public.inventory_commands%rowtype; begin if p_type not in ('opening','migration') or not public.can_post_inventory_transaction(p_t,p_o,p_f) or coalesce(trim(p_idempotency_key),'')='' then raise exception 'Inventory opening command denied'; end if; select ic.* into c from public.inventory_commands ic where ic.tenant_id=p_t and ic.organization_id=p_o and ic.facility_id=p_f and ic.requester_id=auth.uid() and ic.idempotency_key=trim(p_idempotency_key) for update; if found then if c.request_hash<>p_request_hash then raise exception 'Inventory idempotency key was reused with a different request'; end if; return c.id; end if; if jsonb_typeof(p_entries)<>'array' or jsonb_array_length(p_entries)=0 then raise exception 'Inventory opening command denied'; end if; begin insert into public.inventory_commands(tenant_id,organization_id,facility_id,command_type,requester_id,idempotency_key,request_hash,payload,reason) values(p_t,p_o,p_f,p_type,auth.uid(),trim(p_idempotency_key),p_request_hash,p_entries,nullif(trim(p_reason),'')) returning id into c.id; return c.id; exception when unique_violation then select ic.* into c from public.inventory_commands ic where ic.tenant_id=p_t and ic.organization_id=p_o and ic.facility_id=p_f and ic.requester_id=auth.uid() and ic.idempotency_key=trim(p_idempotency_key) for update; if not found or c.request_hash<>p_request_hash then raise exception 'Inventory idempotency key was reused with a different request'; end if; return c.id; end; end $$;
create or replace function public.submit_inventory_command(p_command uuid) returns void language plpgsql security definer set search_path=public as $$ declare c public.inventory_commands%rowtype; begin select ic.* into c from public.inventory_commands ic where ic.id=p_command for update; if not found or c.requester_id<>auth.uid() or c.status<>'draft' or not public.can_post_inventory_transaction(c.tenant_id,c.organization_id,c.facility_id) then raise exception 'Inventory command submission denied'; end if; update public.inventory_commands ic set status='submitted',submitted_at=now() where ic.id=c.id; end $$;
create or replace function public.approve_inventory_command(p_command uuid) returns uuid language plpgsql security definer set search_path=public as $$
declare c public.inventory_commands%rowtype; tx uuid; begin select ic.* into c from public.inventory_commands ic where ic.id=p_command for update; if not found or not public.scope_allowed(c.tenant_id,c.organization_id,c.facility_id) or not (public.has_platform_permission('inventory.approve_opening',c.tenant_id,c.organization_id,c.facility_id) or public.has_platform_permission('platform.full_access',c.tenant_id,c.organization_id,c.facility_id)) or auth.uid()=c.requester_id then raise exception 'Inventory command approval denied'; end if; if c.status='posted' then return c.result_transaction_id; end if; if c.status<>'submitted' then raise exception 'Inventory command approval denied'; end if; insert into public.inventory_transactions(tenant_id,organization_id,facility_id,command_id,transaction_type,posted_by,reason) values(c.tenant_id,c.organization_id,c.facility_id,c.id,c.command_type,auth.uid(),c.reason) returning id into tx; perform public.inventory_post_entries(tx,c.payload,'inventory.transaction_posted',jsonb_build_object('command_id',c.id,'type',c.command_type)); update public.inventory_commands ic set status='posted',approver_id=auth.uid(),approved_at=now(),posted_at=now(),result_transaction_id=tx where ic.id=c.id; return tx; end $$;
create or replace function public.reverse_inventory_transaction(p_original uuid,p_idempotency_key text,p_request_hash text,p_reason text) returns uuid language plpgsql security definer set search_path=public as $$
 declare original_tx public.inventory_transactions%rowtype; c uuid; tx uuid; entries jsonb; begin select t.* into original_tx from public.inventory_transactions t where t.id=p_original for update; if not found or coalesce(trim(p_reason),'')='' or not public.scope_allowed(original_tx.tenant_id,original_tx.organization_id,original_tx.facility_id) or not (public.has_platform_permission('inventory.reverse',original_tx.tenant_id,original_tx.organization_id,original_tx.facility_id) or public.has_platform_permission('platform.full_access',original_tx.tenant_id,original_tx.organization_id,original_tx.facility_id)) then raise exception 'Inventory reversal denied'; end if; select ic.id into c from public.inventory_commands ic where ic.tenant_id=original_tx.tenant_id and ic.organization_id=original_tx.organization_id and ic.facility_id=original_tx.facility_id and ic.requester_id=auth.uid() and ic.idempotency_key=p_idempotency_key for update; if found then if (select request_hash from public.inventory_commands where id=c)<>p_request_hash then raise exception 'Inventory idempotency key was reused with a different request'; end if; return (select result_transaction_id from public.inventory_commands where id=c); end if; if original_tx.reversal_transaction_id is not null then raise exception 'Inventory reversal denied'; end if; select jsonb_agg(jsonb_build_object('profile_id',le.inventory_item_profile_id,'batch_id',le.batch_id,'unit_id',le.inventory_item_unit_id,'channel',le.recording_channel,'account_type',le.account_type,'location_id',le.location_id,'disposition',le.disposition,'quantity_base',-le.quantity_base)) into entries from public.inventory_ledger_entries le where le.transaction_id=original_tx.id; insert into public.inventory_commands(tenant_id,organization_id,facility_id,command_type,status,requester_id,approver_id,idempotency_key,request_hash,payload,reason,submitted_at,approved_at) values(original_tx.tenant_id,original_tx.organization_id,original_tx.facility_id,'reversal','approved',auth.uid(),auth.uid(),p_idempotency_key,p_request_hash,entries,trim(p_reason),now(),now()) returning id into c; insert into public.inventory_transactions(tenant_id,organization_id,facility_id,command_id,transaction_type,posted_by,reason,reverses_transaction_id) values(original_tx.tenant_id,original_tx.organization_id,original_tx.facility_id,c,'reversal',auth.uid(),trim(p_reason),original_tx.id) returning id into tx; perform public.inventory_post_entries(tx,entries,'inventory.transaction_reversed',jsonb_build_object('reverses_transaction_id',original_tx.id,'reason',trim(p_reason))); update public.inventory_commands ic set status='posted',posted_at=now(),result_transaction_id=tx where ic.id=c; perform set_config('app.inventory_transaction_controlled','on',true); update public.inventory_transactions t set reversal_transaction_id=tx where t.id=original_tx.id; return tx; end $$;

create or replace function public.complete_inventory_batch_expiry(p_idempotency_key text,p_request_hash text,p_batch uuid,p_expiry date,p_expiry_status public.inventory_expiry_status,p_reason text) returns uuid language plpgsql security definer set search_path=public as $$
declare b public.inventory_batches%rowtype; ip public.inventory_item_profiles%rowtype; cmd public.inventory_commands%rowtype; tx uuid; begin select ib.* into b from public.inventory_batches ib where ib.id=p_batch for update; select p.* into ip from public.inventory_item_profiles p where p.id=b.inventory_item_profile_id; if not found or not public.can_manage_inventory_item_profile(ip.tenant_id,ip.organization_id,ip.facility_id) or coalesce(trim(p_idempotency_key),'')='' or coalesce(trim(p_reason),'')='' or p_expiry is null or p_expiry_status not in ('known_valid','expired') or (p_expiry_status='known_valid' and p_expiry<=current_date) or (p_expiry_status='expired' and p_expiry>current_date) then raise exception 'Inventory batch expiry completion denied'; end if; select ic.* into cmd from public.inventory_commands ic where ic.tenant_id=ip.tenant_id and ic.organization_id=ip.organization_id and ic.facility_id=ip.facility_id and ic.requester_id=auth.uid() and ic.idempotency_key=p_idempotency_key for update; if found then if cmd.request_hash<>p_request_hash then raise exception 'Inventory idempotency key was reused with a different request'; end if; return cmd.result_transaction_id; end if; if b.expiry_status not in ('pending','unknown_legacy') then raise exception 'Inventory batch expiry completion denied'; end if; begin insert into public.inventory_commands(tenant_id,organization_id,facility_id,command_type,status,requester_id,approver_id,idempotency_key,request_hash,payload,reason,submitted_at,approved_at) values(ip.tenant_id,ip.organization_id,ip.facility_id,'batch_attribute','approved',auth.uid(),auth.uid(),p_idempotency_key,p_request_hash,jsonb_build_object('batch_id',b.id,'expiry_date',p_expiry,'expiry_status',p_expiry_status),trim(p_reason),now(),now()) returning * into cmd; exception when unique_violation then select ic.* into cmd from public.inventory_commands ic where ic.tenant_id=ip.tenant_id and ic.organization_id=ip.organization_id and ic.facility_id=ip.facility_id and ic.requester_id=auth.uid() and ic.idempotency_key=p_idempotency_key for update; if not found or cmd.request_hash<>p_request_hash then raise exception 'Inventory idempotency key was reused with a different request'; end if; return cmd.result_transaction_id; end; insert into public.inventory_transactions(tenant_id,organization_id,facility_id,command_id,transaction_type,posted_by,reason) values(ip.tenant_id,ip.organization_id,ip.facility_id,cmd.id,'batch_attribute',auth.uid(),trim(p_reason)) returning id into tx; perform set_config('app.inventory_batch_controlled','on',true); update public.inventory_batches ib set expiry_date=p_expiry,expiry_status=p_expiry_status,updated_at=now(),updated_by=auth.uid() where ib.id=b.id; perform public.inventory_write_event_and_audit(tx,'inventory.batch_expiry_completed',jsonb_build_object('batch_id',b.id,'expiry_date',p_expiry,'expiry_status',p_expiry_status,'reason',trim(p_reason))); update public.inventory_commands ic set status='posted',posted_at=now(),result_transaction_id=tx where ic.id=cmd.id; return tx; end $$;
create or replace function public.split_inventory_batch_for_expiry(p_idempotency_key text,p_request_hash text,p_parent uuid,p_child_lot text,p_child_expiry date,p_quantity numeric,p_location uuid,p_channel public.inventory_recording_channel,p_disposition public.inventory_stock_disposition,p_reason text) returns uuid language plpgsql security definer set search_path=public as $$
declare b public.inventory_batches%rowtype; ip public.inventory_item_profiles%rowtype; unit_id uuid; child_id uuid; tx uuid; entries jsonb; cmd public.inventory_commands%rowtype; begin select ib.* into b from public.inventory_batches ib where ib.id=p_parent for update; select p.* into ip from public.inventory_item_profiles p where p.id=b.inventory_item_profile_id; if not found or not public.can_manage_inventory_item_profile(ip.tenant_id,ip.organization_id,ip.facility_id) or coalesce(trim(p_idempotency_key),'')='' or coalesce(trim(p_reason),'')='' then raise exception 'Inventory batch split denied'; end if; select ic.* into cmd from public.inventory_commands ic where ic.tenant_id=ip.tenant_id and ic.organization_id=ip.organization_id and ic.facility_id=ip.facility_id and ic.requester_id=auth.uid() and ic.idempotency_key=p_idempotency_key for update; if found then if cmd.request_hash<>p_request_hash then raise exception 'Inventory idempotency key was reused with a different request'; end if; return (cmd.payload->>'result_batch_id')::uuid; end if; select iu.id into unit_id from public.inventory_item_units iu where iu.inventory_item_profile_id=b.inventory_item_profile_id and iu.active and iu.is_base_unit; if not found or b.lot_status<>'known' or p_quantity<=0 or coalesce(trim(p_child_lot),'')='' or p_child_expiry is null or p_child_expiry<=current_date or not exists(select 1 from public.inventory_balance_projections bp where bp.location_id=p_location and bp.inventory_item_profile_id=b.inventory_item_profile_id and bp.batch_id=b.id and bp.recording_channel=p_channel and bp.disposition=p_disposition and bp.quantity_base>=p_quantity) then raise exception 'Inventory batch split denied'; end if; begin insert into public.inventory_commands(tenant_id,organization_id,facility_id,command_type,status,requester_id,approver_id,idempotency_key,request_hash,payload,reason,submitted_at,approved_at) values(ip.tenant_id,ip.organization_id,ip.facility_id,'batch_split','approved',auth.uid(),auth.uid(),p_idempotency_key,p_request_hash,jsonb_build_object('parent_batch_id',b.id),trim(p_reason),now(),now()) returning * into cmd; exception when unique_violation then select ic.* into cmd from public.inventory_commands ic where ic.tenant_id=ip.tenant_id and ic.organization_id=ip.organization_id and ic.facility_id=ip.facility_id and ic.requester_id=auth.uid() and ic.idempotency_key=p_idempotency_key for update; if not found or cmd.request_hash<>p_request_hash then raise exception 'Inventory idempotency key was reused with a different request'; end if; return (cmd.payload->>'result_batch_id')::uuid; end; perform set_config('app.inventory_batch_controlled','on',true); insert into public.inventory_batches(inventory_item_profile_id,manufacturer_name,lot_number,lot_status,expiry_date,expiry_status,parent_batch_id,created_by,updated_by) values(b.inventory_item_profile_id,b.manufacturer_name,trim(p_child_lot),'known',p_child_expiry,'known_valid',b.id,auth.uid(),auth.uid()) returning id into child_id; insert into public.inventory_transactions(tenant_id,organization_id,facility_id,command_id,transaction_type,posted_by,reason) values(ip.tenant_id,ip.organization_id,ip.facility_id,cmd.id,'batch_split',auth.uid(),trim(p_reason)) returning id into tx; entries:=jsonb_build_array(jsonb_build_object('profile_id',b.inventory_item_profile_id,'batch_id',b.id,'unit_id',unit_id,'channel',p_channel,'account_type','physical','location_id',p_location,'disposition',p_disposition,'quantity_base',-p_quantity),jsonb_build_object('profile_id',b.inventory_item_profile_id,'batch_id',b.id,'unit_id',unit_id,'channel',p_channel,'account_type','external_control','quantity_base',p_quantity),jsonb_build_object('profile_id',b.inventory_item_profile_id,'batch_id',child_id,'unit_id',unit_id,'channel',p_channel,'account_type','physical','location_id',p_location,'disposition',p_disposition,'quantity_base',p_quantity),jsonb_build_object('profile_id',b.inventory_item_profile_id,'batch_id',child_id,'unit_id',unit_id,'channel',p_channel,'account_type','external_control','quantity_base',-p_quantity)); perform public.inventory_post_entries(tx,entries,'inventory.batch_split',jsonb_build_object('parent_batch_id',b.id,'child_batch_id',child_id,'quantity_base',p_quantity)); insert into public.inventory_batch_splits(parent_batch_id,child_batch_id,transaction_id,quantity_base,reason,created_by) values(b.id,child_id,tx,p_quantity,trim(p_reason),auth.uid()); update public.inventory_commands ic set status='posted',posted_at=now(),result_transaction_id=tx,payload=ic.payload||jsonb_build_object('result_batch_id',child_id) where ic.id=cmd.id; return child_id; end $$;

alter table public.catalog_items enable row level security; alter table public.catalog_item_identifiers enable row level security; alter table public.inventory_units enable row level security; alter table public.inventory_item_profiles enable row level security; alter table public.inventory_item_units enable row level security; alter table public.inventory_locations enable row level security; alter table public.inventory_location_attributes enable row level security; alter table public.inventory_batches enable row level security; alter table public.inventory_batch_splits enable row level security; alter table public.inventory_commands enable row level security; alter table public.inventory_transactions enable row level security; alter table public.inventory_ledger_entries enable row level security; alter table public.inventory_balance_projections enable row level security; alter table public.inventory_events enable row level security;
create policy inventory_catalog_read on public.catalog_items for select using(auth.uid() is not null); create policy inventory_identifier_read on public.catalog_item_identifiers for select using(auth.uid() is not null); create policy inventory_units_read on public.inventory_units for select using(auth.uid() is not null);
create policy inventory_profiles_read on public.inventory_item_profiles for select using(public.scope_allowed(tenant_id,organization_id,facility_id) and (public.has_platform_permission('inventory.view',tenant_id,organization_id,facility_id) or public.can_manage_inventory_item_profile(tenant_id,organization_id,facility_id) or public.has_platform_permission('platform.full_access',tenant_id,organization_id,facility_id)));
create policy inventory_units_profile_read on public.inventory_item_units for select using(exists(select 1 from public.inventory_item_profiles ip where ip.id=inventory_item_profile_id and public.scope_allowed(ip.tenant_id,ip.organization_id,ip.facility_id)));
create policy inventory_locations_read on public.inventory_locations for select using(public.can_view_inventory_location(id)); create policy inventory_location_attributes_read on public.inventory_location_attributes for select using(public.can_view_inventory_location(location_id));
create policy inventory_batches_read on public.inventory_batches for select using(exists(select 1 from public.inventory_item_profiles ip where ip.id=inventory_item_profile_id and public.scope_allowed(ip.tenant_id,ip.organization_id,ip.facility_id) and (public.has_platform_permission('inventory.view',ip.tenant_id,ip.organization_id,ip.facility_id) or public.can_manage_inventory_item_profile(ip.tenant_id,ip.organization_id,ip.facility_id))));
create policy inventory_batch_splits_read on public.inventory_batch_splits for select using(exists(select 1 from public.inventory_batches b join public.inventory_item_profiles ip on ip.id=b.inventory_item_profile_id where b.id=parent_batch_id and public.scope_allowed(ip.tenant_id,ip.organization_id,ip.facility_id)));
create policy inventory_commands_read on public.inventory_commands for select using(public.can_view_inventory_command(id)); create policy inventory_transactions_read on public.inventory_transactions for select using(public.can_view_inventory_transaction(id)); create policy inventory_ledger_read on public.inventory_ledger_entries for select using(public.can_view_inventory_ledger_entry(id)); create policy inventory_projection_read on public.inventory_balance_projections for select using(public.can_view_inventory_location(location_id)); create policy inventory_events_read on public.inventory_events for select using(public.can_view_inventory_transaction(transaction_id));

